        for (int k = 0; k < K; ++k) {
            sum += A[row * K + k] * B[k * N + col];
        }
        C[row * N + col] = sum;
    }
}

// ============================================================================
// Kernel 1: SlicedK SGEMM (float32) - Grid-stride loop over K
// ============================================================================
__global__ void sgemm_sliced_k(
    const float* __restrict__ A,
    const float* __restrict__ B,
    float* __restrict__ C,
    int M, int N, int K)
{
    int row = blockIdx.y * blockDim.y + threadIdx.y;
    int col = blockIdx.x * blockDim.x + threadIdx.x;

    if (row < M && col < N) {
        float sum = 0.0f;
        // Grid-stride loop over K for better memory coalescing
        for (int k = 0; k < K; k += 8) {
            #pragma unroll
            for (int kk = 0; kk < 8 && (k + kk) < K; ++kk) {
                sum += A[row * K + k + kk] * B[(k + kk) * N + col];
            }
        }
        C[row * N + col] = sum;
    }
}

// ============================================================================
// Kernel 2: Tiled 8x8 Block Column Format SGEMM (float32)
// ============================================================================
#define TILE_SIZE 8

__global__ void sgemm_tiled_8x8(
    const float* __restrict__ A,
    const float* __restrict__ B,
    float* __restrict__ C,
    int M, int N, int K)
{
    __shared__ float As[TILE_SIZE][TILE_SIZE];
    __shared__ float Bs[TILE_SIZE][TILE_SIZE];

    int bx = blockIdx.x;
    int by = blockIdx.y;
    int tx = threadIdx.x;
    int ty = threadIdx.y;

    int row = by * TILE_SIZE + ty;
    int col = bx * TILE_SIZE + tx;

    float sum = 0.0f;

    int numTiles = (K + TILE_SIZE - 1) / TILE_SIZE;

    for (int t = 0; t < numTiles; ++t) {
        // Load tiles into shared memory
        int a_col = t * TILE_SIZE + tx;
        int b_row = t * TILE_SIZE + ty;

        As[ty][tx] = (row < M && a_col < K) ? A[row * K + a_col] : 0.0f;
        Bs[ty][tx] = (b_row < K && col < N) ? B[b_row * N + col] : 0.0f;

        __syncthreads();

        #pragma unroll
        for (int k = 0; k < TILE_SIZE; ++k) {
            sum += As[ty][k] * Bs[k][tx];
        }

        __syncthreads();
    }

    if (row < M && col < N) {
        C[row * N + col] = sum;
    }
}

// ============================================================================
// Kernel 3: WMMA FP32 Accumulator (float32)
// Using standard FP32/FP16 tensor core path
// ============================================================================
#define WMMA_M 16
#define WMMA_N 16
#define WMMA_K 16

__global__ void sgemm_wmma_tf32(
    const float* __restrict__ A,
    const float* __restrict__ B,
    float* __restrict__ C,
    int M, int N, int K)
{
    // For FP32 inputs, we'll use a tiled approach with shared memory
    // Since direct FP32 tensor cores need careful handling
    __shared__ float As[16][16];
    __shared__ float Bs[16][16];

    int warpM = blockIdx.y;
    int warpN = blockIdx.x;
    int laneId = threadIdx.x % 32;

    int warp_row = warpM * 16;
    int warp_col = warpN * 16;

    if (warp_row >= M || warp_col >= N) return;

    float acc = 0.0f;

    int row = warp_row + laneId / 16 * 4 + (laneId % 4);
    int col = warp_col + (laneId / 4) % 4 * 4 + (laneId % 4);

    int numTiles = (K + 15) / 16;

    for (int t = 0; t < numTiles; ++t) {
        int k_offset = t * 16;

        // Load A tile
        if (laneId < 16) {
            int a_row = warp_row + laneId;
            for (int i = 0; i < 16; ++i) {
                int a_col = k_offset + i;
                As[laneId][i] = (a_row < M && a_col < K) ? A[a_row * K + a_col] : 0.0f;
            }
        }

        // Load B tile
        if (laneId < 16) {
            int b_row = k_offset + laneId;
            for (int j = 0; j < 16; ++j) {
                int b_col = warp_col + j;
                Bs[laneId][j] = (b_row < K && b_col < N) ? B[b_row * N + b_col] : 0.0f;
            }
        }

        __syncthreads();

        // Compute
        #pragma unroll
        for (int k = 0; k < 16; ++k) {
            if (row < M && col < N && (k_offset + k) < K) {
                acc += As[row - warp_row][k] * Bs[k][col - warp_col];
            }
        }

        __syncthreads();
    }

    if (row < M && col < N) {
        C[row * N + col] = acc;
    }
}

// ============================================================================
// Kernel 4: Naive HGEMM (float16)
// ============================================================================
__global__ void hgemm_naive(
    const half* __restrict__ A,
