// ============================================================================
// Kernel 6: MMA Tensor Core Stage 2 (float16) with half precision
// ============================================================================
#define WMMA_M 16
#define WMMA_N 16
#define WMMA_K 16

__global__ void hgemm_mma_stage2(
    const half* __restrict__ A,
    const half* __restrict__ B,
    half* __restrict__ C,
    int M, int N, int K)
{
