extern "C" void cuda_kernel(
    void* a_ptr,
    void* b_ptr,
    void* c_ptr,
    int M,
    int N,
    int K,
    int op_type)
{
    // Choose kernel based on op_type
    switch (op_type) {
        case 0: { // Naive SGEMM
            dim3 block(16, 16);
            dim3 grid((N + block.x - 1) / block.x, (M + block.y - 1) / block.y);
            sgemm_naive<<<grid, block>>>(
                (const float*)a_ptr,
                (const float*)b_ptr,
                (float*)c_ptr,
                M, N, K);
            break;
        }
        case 1: { // SlicedK SGEMM
