// ============================================================================
// Kernel 7: MMA Tensor Core Stage 1 (float16) - Single stage with float accumulator
// ============================================================================
__global__ void hgemm_mma_stage1(
    const half* __restrict__ A,
    const half* __restrict__ B,
    half* __restrict__ C,
    int M, int N, int K)
{
    // Use tensor cores with half input, float accumulator
    int warpM = (blockIdx.y * blockDim.y + threadIdx.y) / 32;
    int warpN = (blockIdx.x * blockDim.x + threadIdx.x);

    int warp_row = warpM * WMMA_M;
    int warp_col = warpN * WMMA_N;

    if (warp_row >= M || warp_col >= N) return;

    wmma::fragment<wmma::matrix_a, WMMA_M, WMMA_N, WMMA_K, half, wmma::row_major> a_frag;
    wmma::fragment<wmma::matrix_b, WMMA_M, WMMA_N, WMMA_K, half, wmma::row_major> b_frag;
    wmma::fragment<wmma::accumulator, WMMA_M, WMMA_N, WMMA_K, float> c_frag;

    wmma::fill_fragment(c_frag, 0.0f);

    int numTiles = (K + WMMA_K - 1) / WMMA_K;

    for (int t = 0; t < numTiles; ++t) {
        int k_offset = t * WMMA_K;

        if (warp_row + WMMA_M <= M && k_offset + WMMA_K <= K) {
            wmma::load_matrix_sync(a_frag, A + warp_row * K + k_offset, K);
        } else {
            wmma::fill_fragment(a_frag, __float2half(0.0f));
        }

        if (k_offset + WMMA_K <= K && warp_col + WMMA_N <= N) {
            wmma::load_matrix_sync(b_frag, B + k_offset * N + warp_col, N);
        } else {
            wmma::fill_fragment(b_frag, __float2half(0.0f));
        }

        wmma::mma_sync(c_frag, a_frag, b_frag, c_frag);
    }

    // Store float accumulator to shared memory, then convert to half
    __shared__ float smem[WMMA_M * WMMA_N];

    if (warp_row + WMMA_M <= M && warp_col + WMMA_N <= N) {
        wmma::store_matrix_sync(smem, c_frag, WMMA_N, wmma::mem_row_major);

        __syncthreads();

        // Each thread converts and writes out some elements
        int tid = threadIdx.x + threadIdx.y * blockDim.x;
        int num_elems = WMMA_M * WMMA_N;

        for (int i = tid; i < num_elems; i += blockDim.x * blockDim.y) {
            int local_row = i / WMMA_N;
            int local_col = i % WMMA_N;
            int global_row = warp_row + local_row;
            int global_col = warp_col + local_col;

            if (global_row < M && global_col < N) {
                C[global_row * N + global_col] = __float2half(smem[i]);
            }
        }
    }
}
